import React from 'react';

const RegionalBreakdown = ({ regions, onRegionClick, selectedRegion }) => {

  const formatBillions = (value) => `$${value.toFixed(1)}B`;
  const formatMillions = (value) => `$${value.toFixed(0)}M`;

  const getSparklineData = (submissionCount, approvedCount) => {
    // Generate simple sparkline based on approval rate
    const approvalRate = approvedCount / submissionCount;
    const bars = 5;

    return Array.from({ length: bars }, (_, i) => {
      const variance = Math.random() * 0.3;
      return Math.min(100, (approvalRate + variance) * 100);
    });
  };

  const getRegionColor = (region) => {
    const colorMap = {
      'North America': '#FF5F02',
      'EMEA': '#3B82F6',
      'APAC': '#06B6D4',
      'Latin America': '#22C55E'
    };
    return colorMap[region] || '#999';
  };

  return (
    <div className="region-strip">
      {regions.map((region) => {
        const sparkline = getSparklineData(region.submission_count, region.approved_count);
        const isSelected = selectedRegion === region.Global_Region;

        return (
          <div 
            key={region.Global_Region}
            className={`region-block ${isSelected ? 'selected' : ''}`}
            onClick={() => onRegionClick(region.Global_Region)}
          >
            <div className="region-name">{region.Global_Region}</div>
            <div className="region-value" style={{ color: getRegionColor(region.Global_Region) }}>
              {region.approved_count} Approved
              {region.delayed_count > 0 && ` · ${region.delayed_count} Delayed`}
            </div>
            <div className="region-sub">
              {formatBillions(region.pipeline_billions)} pipeline
              {region.revenue_at_risk_millions > 0 && (
                <> · {formatMillions(region.revenue_at_risk_millions)} at risk</>
              )}
            </div>

            {/* Sparkline */}
            <div className="sparkline">
              {sparkline.map((height, i) => (
                <div 
                  key={i}
                  className="spark-bar"
                  style={{ 
                    height: `${height}%`,
                    background: region.delayed_count > region.approved_count 
                      ? 'rgba(239, 68, 68, 0.6)' 
                      : 'rgba(34, 197, 94, 0.6)'
                  }}
                ></div>
              ))}
            </div>
          </div>
        );
      })}

      {/* Portfolio Total */}
      <div className="region-block portfolio-total">
        <div className="region-name">Portfolio Total</div>
        <div className="region-value">
          {formatBillions(regions.reduce((sum, r) => sum + r.pipeline_billions, 0))}
        </div>
        <div className="region-sub">
          {formatMillions(regions.reduce((sum, r) => sum + r.revenue_at_risk_millions, 0))} at risk ·{' '}
          {regions.reduce((sum, r) => sum + r.delayed_count, 0)} interventions needed
        </div>
        <div className="sparkline">
          {[35, 55, 60, 78, 100].map((height, i) => (
            <div 
              key={i}
              className="spark-bar"
              style={{ height: `${height}%` }}
            ></div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default RegionalBreakdown;
